from typing import List
from collections import defaultdict

class Solution:
    def countPairs(self, nums: List[int], low: int, high: int) -> int:
        count = 0
        xor_counts = defaultdict(int)

        for num in nums:
            for x in xor_counts:
                xor = num ^ x
                if low <= xor <= high:
                    count += xor_counts[x]
            xor_counts[num] += 1

        return count
